<?php
define('KEY', 'ibook2026deploy');
if (($_GET['key'] ?? '') !== KEY) { http_response_code(403); die('Akses ditolak.'); }
header('Content-Type: text/html; charset=utf-8');
$target = __DIR__ . '/resources/views/tempahan/index.blade.php';
$content = base64_decode('');
if (file_put_contents($target, $content) !== false) {
    echo '<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="font-family:monospace;background:#1a1a2e;color:#e5e7eb;padding:30px">';
    echo '<h2 style="color:#f59e0b">iBook 2.0 — Fix index.blade.php</h2><pre>';
    echo '<span style="color:#34d399">[OK]</span> index.blade.php (' . strlen($content) . ' bytes) ditulis.</pre>';
    // Padam blade cache
    $vd = __DIR__ . '/storage/framework/views'; $cl = 0;
    if (is_dir($vd)) foreach (glob($vd . '/*.php') as $f) if (@unlink($f)) $cl++;
    echo '<pre><span style="color:#34d399">[OK]</span> ' . $cl . ' fail blade cache dipadam.</pre>';
    echo '<form method="post" action="?key=ibook2026deploy&delete=1" style="margin-top:16px"><button style="background:#991b1b;color:#fff;border:none;padding:8px 18px;border-radius:6px;cursor:pointer">&#128465; Padam fix-index.php</button></form>';
    if ($_SERVER['REQUEST_METHOD'] === 'POST' && ($_GET['delete'] ?? '') === '1') {
        @unlink(__FILE__);
        echo '<p style="color:#34d399;font-family:monospace">&#10003; Dipadamkan.</p>';
    }
    echo '</body></html>';
} else {
    echo '<h2 style="color:#f87171">GAGAL tulis fail!</h2>';
}